from django.core.management.base import BaseCommand
from myapp.models import Paper, BlogPost, Scholarship
from datetime import date


class Command(BaseCommand):
    help = 'Seed database with sample scholarships, blog posts and papers'

    def handle(self, *args, **options):
        self._seed_scholarships()
        self._seed_blog_posts()
        self._seed_papers()
        self.stdout.write(self.style.SUCCESS('All data seeded successfully!'))

