            Scholarship(title='Chinese Government Scholarship — Study in China', slug='chinese-government-scholarship-2026', region='asia', country='China', description='Full scholarship by the Chinese Ministry of Education covering tuition, accommodation, health insurance and monthly stipend.', content='<h3>Eligibility</h3><p>Open to all international students. Must have high school diploma or bachelor\'s degree depending on program.</p>', deadline=date(2026, 5, 30)),
            Scholarship(title='DAAD Scholarship — Study in South Korea', slug='daad-scholarship-south-korea', region='asia', country='South Korea', description='DAAD Korea offers scholarships for graduate studies at Korean universities with full funding.', content='', deadline=date(2026, 8, 15)),
