            Scholarship(title='Chevening Scholarship — Study in the UK', slug='chevening-scholarship-uk-2026', region='europe', country='United Kingdom', description='Fully funded UK government scholarship for one-year master\'s degrees, covering tuition, living expenses, and airfare.', content='<h3>Eligibility</h3><p>Applicants must have a strong academic background, leadership potential, and at least two years of work experience.</p>', deadline=date(2026, 11, 5)),
            Scholarship(title='DAAD Scholarship — Study in Germany 2026', slug='daad-scholarship-germany-2026', region='europe', country='Germany', description='Fully funded DAAD scholarships for international students to pursue master\'s or PhD in Germany.', content='', deadline=date(2026, 9, 30)),
