            Scholarship(title='Vanier Canada Graduate Scholarship', slug='vanier-scholarship-canada-2026', region='north-america', country='Canada', description='$50,000 per year for three years for PhD students at Canadian universities.', content='', deadline=date(2026, 11, 1)),
