            BlogPost(title='How to Write a Winning Scholarship Essay', slug='winning-scholarship-essay-guide', category='Guide', excerpt='Learn the key strategies to craft a compelling scholarship application essay that stands out.', content='<p>Writing a scholarship essay is your chance to tell your story. Start with a strong opening, highlight your achievements, and explain why you deserve the scholarship. Be authentic and proofread multiple times.</p><p>Most importantly, tailor each essay to the specific scholarship you are applying for.</p>'),
            BlogPost(title='Top 10 Fully Funded Scholarships for 2026', slug='top-10-fully-funded-scholarships-2026', category='News', excerpt='A curated list of the best fully funded scholarships available for international students in 2026.', content='<p>We\'ve compiled the top 10 fully funded scholarships including MEXT, Chevening, Erasmus Mundus, DAAD, and Fulbright. Each offers full tuition and living expenses.</p><p>Apply early and prepare your documents in advance.</p>'),
            BlogPost(title='5 Tips for Acing Your Scholarship Interview', slug='scholarship-interview-tips', category='Tips', excerpt='Prepare with confidence using these expert tips for scholarship interviews.', content='<p>1. Research the scholarship thoroughly. 2. Practice common questions. 3. Dress professionally. 4. Show enthusiasm. 5. Ask thoughtful questions at the end.</p>'),
            BlogPost(title='Study in Germany: A Complete Guide for 2026', slug='study-in-germany-guide-2026', category='Guide', excerpt='Everything you need to know about applying to German universities as an international student.', content='<p>Germany offers world-class education with low or no tuition fees. This guide covers the application process, visa requirements, student visa, blocked account, and health insurance.</p>'),
